import { GoogleGenAI, Type } from "@google/genai";
import { ConversionResult } from "../types";

export const convertToLatexHtml = async (
  base64Images: string[],
  textContext: string = ""
): Promise<ConversionResult> => {
  // Khởi tạo GoogleGenAI. Lưu ý: process.env.API_KEY được tiêm tự động trong môi trường này.
  // Khi deploy lên Vercel, bạn phải cài đặt biến môi trường tên là API_KEY.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const modelName = 'gemini-3-flash-preview';

  const imageParts = base64Images.map(base64 => ({
    inlineData: {
      mimeType: 'image/jpeg',
      data: base64.split(',')[1] || base64
    }
  }));

  const textPart = {
    text: `Bạn là một trợ lý chuyển đổi tài liệu thông minh. 
    Nhiệm vụ của bạn là đọc hình ảnh hoặc văn bản và chuyển đổi chúng sang định dạng văn bản thuần có nhúng mã LaTeX đơn giản.

    QUY TẮC QUAN TRỌNG:
    1. Chữ viết: Giữ nguyên tiếng Việt thông thường.
    2. Toán học & Kỹ thuật: TẤT CẢ các con số (1, 2, 3...), các biến số (x, y, z...), các tham số (a, b, m...), các đơn vị đo (cm, m, kg...), và công thức toán học PHẢI được bao bọc bởi dấu $ (ví dụ: $x$, $5$, $y = f(x)$).
    3. Định dạng đầu ra:
       - Trường "latex": Trả về văn bản thuần túy (Plain Text) có chứa mã LaTeX bên trong dấu $. KHÔNG bao gồm các lệnh định dạng trang như \\documentclass hay \\begin{document}. Chỉ là nội dung văn bản.
       - Trường "html": Trả về nội dung tương tự nhưng ở định dạng HTML đơn giản (sử dụng các thẻ <p>, <br>, <b> nếu cần). Các công thức vẫn giữ nguyên dấu $.

    Ví dụ mong muốn:
    Đầu vào: "Cho hàm số y = f(x) có tập xác định D."
    Đầu ra (latex): "Cho hàm số $y = f(x)$ có tập xác định $D$."
    Đầu ra (html): "<p>Cho hàm số $y = f(x)$ có tập xác định $D$.</p>"

    Bối cảnh văn bản trích xuất được: ${textContext}

    Trả về kết quả dưới dạng JSON.`
  };

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: { parts: [...imageParts, textPart] },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            latex: { type: Type.STRING },
            html: { type: Type.STRING },
          },
          required: ["latex", "html"]
        }
      }
    });

    return JSON.parse(response.text || "{}") as ConversionResult;
  } catch (error: any) {
    console.error("Gemini conversion error:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { FileType, ProcessingFile, ConversionResult } from './types';
import { pdfToImages, docxToHtmlAndImages, downloadFile } from './utils/converters';
