declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }
  interface Window {
    aistudio?: AIStudio;
  }
}

const App: React.FC = () => {
  const [currentFile, setCurrentFile] = useState<ProcessingFile | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeTab, setActiveTab] = useState<'latex' | 'html'>('latex');
  const [isAIStudioEnv, setIsAIStudioEnv] = useState<boolean>(false);

  useEffect(() => {
    if (window.aistudio && typeof window.aistudio.openSelectKey === 'function') {
      setIsAIStudioEnv(true);
    }
  }, []);

  const handleSelectKey = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
    } else {
      alert("Hướng dẫn Vercel: Truy cập Project Settings -> Environment Variables. Thêm Key là 'API_KEY' và dán Gemini API Key của bạn vào Value. Sau đó Redeploy dự án.");
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const type = file.type as FileType;
    if (type !== FileType.PDF && type !== FileType.DOCX) {
      alert("Vui lòng chỉ tải lên tệp PDF hoặc DOCX.");
      return;
    }

    setCurrentFile({
      file,
      type,
      status: 'idle',
      progress: 0
    });
  };

  const processFile = async () => {
    if (!currentFile) return;

    setIsProcessing(true);
    setCurrentFile(prev => prev ? { ...prev, status: 'processing', progress: 10, error: undefined } : null);

    try {
      let images: string[] = [];
      let context = "";

      if (currentFile.type === FileType.PDF) {
        setCurrentFile(prev => prev ? { ...prev, progress: 30 } : null);
        images = await pdfToImages(currentFile.file);
      } else {
        setCurrentFile(prev => prev ? { ...prev, progress: 30 } : null);
        const docResult = await docxToHtmlAndImages(currentFile.file);
        context = docResult.html;
        images = docResult.images.slice(0, 5); 
      }

      setCurrentFile(prev => prev ? { ...prev, progress: 60 } : null);

      const result = await convertToLatexHtml(images, context);

      setCurrentFile(prev => prev ? { 
        ...prev, 
        status: 'completed', 
        progress: 100, 
        result 
      } : null);
    } catch (err: any) {
      let errorMessage = err.message || "Đã xảy ra lỗi không xác định";

      if (errorMessage.includes("Requested entity was not found") || 
          errorMessage.includes("API_KEY") || 
          errorMessage.includes("API key not found") ||
          errorMessage.includes("API_KEY_INVALID")) {
        errorMessage = "Thiếu hoặc sai API Key. Nếu bạn dùng Vercel, hãy vào Settings -> Environment Variables, thêm biến 'API_KEY' và Redeploy lại.";
      }

      setCurrentFile(prev => prev ? { 
        ...prev, 
        status: 'error', 
        error: errorMessage 
      } : null);
    } finally {
      setIsProcessing(false);
    }
  };

  const reset = () => {
    setCurrentFile(null);
    setIsProcessing(false);
  };

  return (
    <div className="max-w-5xl mx-auto px-4 py-10 min-h-screen flex flex-col selection:bg-blue-100">
      <header className="mb-10 flex flex-wrap items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">
            Doc2Latex <span className="text-blue-600">Simple</span>
          </h1>
          <p className="text-slate-500 mt-1 font-medium italic">Chuyển đổi văn bản kèm công thức toán chuẩn $...$</p>
        </div>

        <div className="flex items-center gap-3">
          {!isAIStudioEnv && (
            <span className="hidden md:inline-flex items-center px-3 py-1 bg-amber-50 text-amber-600 text-[10px] font-bold uppercase tracking-widest border border-amber-100 rounded-lg">
              Chế độ Vercel/GitHub
            </span>
          )}
          <button 
            onClick={handleSelectKey}
            className="px-5 py-2.5 bg-slate-900 text-white rounded-xl text-sm font-bold hover:bg-slate-800 transition-all shadow-lg active:scale-95"
          >
            Cấu hình API Key
          </button>
        </div>
      </header>

      <main className="flex-grow">
        {!currentFile ? (
          <div className="bg-white border-4 border-dashed border-slate-200 rounded-[2.5rem] p-20 text-center hover:border-blue-400 hover:bg-blue-50/10 transition-all cursor-pointer group" onClick={() => document.getElementById('file-input')?.click()}>
            <input id="file-input" type="file" className="hidden" accept=".docx,.pdf" onChange={handleFileUpload} />
            <div className="w-24 h-24 bg-blue-50 text-blue-500 rounded-3xl flex items-center justify-center mx-auto mb-8 group-hover:scale-110 transition-transform">
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" className="w-12 h-12">
                <path strokeLinecap="round" strokeLinejoin="round" d="M19.5 14.25v-2.625a3.375 3.375 0 0 0-3.375-3.375h-1.5A1.125 1.125 0 0 1 13.5 7.125v-1.5a3.375 3.375 0 0 0-3.375-3.375H8.25m3.75 9v6m3-3H9m1.5-12H5.625c-.621 0-1.125.504-1.125 1.125v17.25c0 .621.504 1.125 1.125 1.125h12.75c.621 0 1.125-.504 1.125-1.125V11.25a9 9 0 0 0-9-9Z" />
              </svg>
            </div>
            <h2 className="text-2xl font-black text-slate-800 mb-2">Tải tệp PDF hoặc Word lên</h2>
            <p className="text-slate-400 font-medium">Nhấn để chọn tệp cần trích xuất toán học</p>
          </div>
        ) : (
          <div className="bg-white rounded-[2rem] shadow-2xl border border-slate-100 overflow-hidden flex flex-col h-[75vh]">
            {/* Header file info */}
            <div className="bg-slate-50 border-b border-slate-200 p-6 flex items-center justify-between">
              <div className="flex items-center gap-4">
                <div className={`p-3 rounded-xl ${currentFile.type === FileType.PDF ? 'bg-red-500' : 'bg-blue-500'} text-white`}>
                  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-6 h-6">
                    <path fillRule="evenodd" d="M5.625 1.5c-1.036 0-1.875.84-1.875 1.875v17.25c0 1.035.84 1.875 1.875 1.875h12.75c1.035 0 1.875-.84 1.875-1.875V11.25a9 9 0 0 0-9-9h-5.625ZM12 4.5V11.25a.75.75 0 0 0 .75.75h6.75a7.5 7.5 0 0 0-7.5-7.5Z" clipRule="evenodd" />
                  </svg>
                </div>
                <div>
                  <h3 className="font-bold text-slate-900 truncate max-w-[200px] sm:max-w-md">{currentFile.file.name}</h3>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">{currentFile.type === FileType.PDF ? 'Tài liệu PDF' : 'Tài liệu Word'}</p>
                </div>
              </div>

              {currentFile.status === 'idle' && (
                <button onClick={processFile} className="bg-blue-600 text-white px-8 py-3 rounded-2xl font-black hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all">BẮT ĐẦU CHUYỂN</button>
              )}
              {currentFile.status === 'completed' && (
                <button onClick={reset} className="bg-slate-200 text-slate-600 px-6 py-2.5 rounded-xl font-bold hover:bg-slate-300 transition-colors">Đổi tệp</button>
              )}
            </div>

            {/* Content area */}
            <div className="flex-grow overflow-hidden flex flex-col">
              {currentFile.status === 'processing' && (
                <div className="flex-grow flex flex-col items-center justify-center p-20">
                  <div className="relative w-24 h-24 mb-8">
                    <div className="absolute inset-0 border-8 border-blue-50 rounded-full"></div>
                    <div className="absolute inset-0 border-8 border-blue-600 rounded-full border-t-transparent animate-spin"></div>
                  </div>
                  <h4 className="text-xl font-bold text-slate-800">Đang nhận diện công thức...</h4>
                  <p className="text-slate-400 mt-2">Tiến trình: {currentFile.progress}%</p>
                </div>
              )}

              {currentFile.status === 'error' && (
                <div className="flex-grow p-12 text-center">
                  <div className="text-red-500 mb-6">
                    <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-16 h-16 mx-auto">
                      <path strokeLinecap="round" strokeLinejoin="round" d="M12 9v3.75m9-.75a9 9 0 1 1-18 0 9 9 0 0 1 18 0Zm-9 3.75h.008v.008H12v-.008Z" />
                    </svg>
                  </div>
                  <h4 className="text-2xl font-bold text-slate-900 mb-4">Ối! Đã xảy ra lỗi</h4>
                  <p className="text-slate-500 max-w-md mx-auto mb-8 leading-relaxed">{currentFile.error}</p>
                  <button onClick={processFile} className="bg-slate-900 text-white px-10 py-4 rounded-2xl font-bold shadow-lg">Thử lại lần nữa</button>
