                    >
                      Dạng LaTeX (MathType)
                    </button>
                    <button 
                      onClick={() => setActiveTab('html')}
                      className={`px-8 py-5 text-xs font-black uppercase tracking-[0.2em] transition-all border-b-2 ${activeTab === 'html' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-400'}`}
                    >
                      Xem Preview HTML
                    </button>

                    <button 
                      onClick={() => {
                        const content = activeTab === 'latex' ? currentFile.result?.latex : currentFile.result?.html;
                        navigator.clipboard.writeText(content || "");
                        alert("Đã sao chép nội dung!");
                      }}
                      className="ml-auto flex items-center gap-2 text-xs font-bold text-blue-600 hover:text-blue-700 px-4"
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-4 h-4">
                        <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 17.25v3.375c0 .621-.504 1.125-1.125 1.125h-9.75a1.125 1.125 0 0 1-1.125-1.125V7.875c0-.621.504-1.125 1.125-1.125H6.75a9.06 9.06 0 0 1 1.5.124m7.5 10.376h3.375c.621 0 1.125-.504 1.125-1.125V11.25c0-4.46-3.243-8.161-7.5-8.876a9.06 9.06 0 0 0-1.5-.124H9.375c-.621 0-1.125.504-1.125 1.125v3.5m7.5 10.375H9.375a1.125 1.125 0 0 1-1.125-1.125v-9.25m12 6.625v-1.875a3.375 3.375 0 0 0-3.375-3.375h-1.5a1.125 1.125 0 0 1-1.125-1.125v-1.5a3.375 3.375 0 0 0-3.375-3.375H9.75" />
