    YÊU CẦU CỰC KỲ QUAN TRỌNG:
    1. GIỮ NGUYÊN CẤU TRÚC: Phải giữ đúng các đoạn văn, ngắt dòng (\n), danh sách và thứ tự nội dung như bản gốc. Không được tóm tắt hay lược bỏ văn bản.
    2. CHUẨN TOÁN HỌC: TẤT CẢ các con số đơn lẻ, biến số (x, y, n...), tham số (a, b, m...), các biểu thức và công thức toán học PHẢI được bao bọc bởi dấu $. 
       - Ví dụ: "Câu 1. Cho x = 5" -> "Câu $1$. Cho $x = 5$".
       - Ví dụ: "Diện tích S = 10m2" -> "Diện tích $S = 10m^2$".
    3. HÌNH ẢNH: Nếu thấy vị trí có hình ảnh (placeholder hoặc dựa vào ngữ cảnh), hãy đánh dấu bằng [HÌNH VẼ: mô tả ngắn gọn].
    4. ĐỊA CHỈ ĐẦU RA:
       - Trường "latex": Trả về văn bản thuần túy đã xử lý $, giữ nguyên các ký tự ngắt dòng (\n) để copy-paste vào Word/MathType.
       - Trường "html": Trả về HTML tương ứng, giữ nguyên cấu trúc các đoạn văn (<p>), in đậm (<b>), xuống dòng (<br>).

    Văn bản gốc cần xử lý:
    ${textContext}

    Hãy trả về kết quả dưới dạng JSON.`
  };

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: { parts: [...imageParts, textPart] },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            latex: { type: Type.STRING },
            html: { type: Type.STRING },
          },
          required: ["latex", "html"]
        }
      }
    });

    return JSON.parse(response.text || "{}") as ConversionResult;
  } catch (error: any) {
    console.error("Gemini conversion error:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { FileType, ProcessingFile, ConversionResult } from './types';
import { pdfToImages, docxToHtmlAndImages, downloadFile } from './utils/converters';
import { convertToLatexHtml } from './services/gemini';

declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }
  interface Window {
    aistudio?: AIStudio;
  }
}

const App: React.FC = () => {
  const [currentFile, setCurrentFile] = useState<ProcessingFile | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeTab, setActiveTab] = useState<'latex' | 'html'>('latex');
  const [isAIStudioEnv, setIsAIStudioEnv] = useState<boolean>(false);

  useEffect(() => {
    if (window.aistudio && typeof window.aistudio.openSelectKey === 'function') {
      setIsAIStudioEnv(true);
    }
  }, []);

  const handleSelectKey = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
    } else {
      alert("Hướng dẫn Vercel: Truy cập Project Settings -> Environment Variables. Thêm Key là 'API_KEY' và dán Gemini API Key của bạn vào Value. Sau đó Redeploy dự án.");
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const type = file.type as FileType;
    if (type !== FileType.PDF && type !== FileType.DOCX) {
      alert("Vui lòng chỉ tải lên tệp PDF hoặc DOCX.");
      return;
    }

    setCurrentFile({
      file,
      type,
      status: 'idle',
      progress: 0
    });
