          <button 
            onClick={handleSelectKey}
            className="px-5 py-2.5 bg-white border border-slate-200 text-slate-700 rounded-xl text-xs font-bold hover:bg-slate-50 transition-all shadow-sm active:scale-95"
          >
            Cấu hình API Key
          </button>
        </div>
      </header>

      <main className="flex-grow">
        {!currentFile ? (
          <div className="bg-white border-2 border-dashed border-slate-300 rounded-[2rem] p-16 text-center hover:border-blue-500 hover:bg-blue-50/20 transition-all cursor-pointer group" onClick={() => document.getElementById('file-input')?.click()}>
            <input id="file-input" type="file" className="hidden" accept=".docx,.pdf" onChange={handleFileUpload} />
