              <div className="flex gap-2">
                {currentFile.status === 'idle' && (
                  <button onClick={processFile} className="bg-blue-600 text-white px-6 py-2 rounded-xl text-sm font-bold hover:bg-blue-700 transition-all shadow-md">Chuyển đổi ngay</button>
                )}
                {currentFile.status === 'completed' && (
                  <button onClick={reset} className="text-slate-500 hover:text-slate-800 text-sm font-bold px-4 transition-colors">Chọn file khác</button>
