                        </svg>
                        Tải file Word (.doc)
                      </button>
                      <button 
                        onClick={() => {
                          const content = activeTab === 'latex' ? currentFile.result?.latex : currentFile.result?.html;
                          navigator.clipboard.writeText(content || "");
