export const convertToLatexHtml = async (
  base64Images: string[],
  textContext: string = ""
): Promise<ConversionResult> => {
  // Khởi tạo instance mới mỗi lần gọi để đảm bảo lấy API Key mới nhất từ dialog
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-pro-preview';

  const imageParts = base64Images.map(base64 => ({
    inlineData: {
      mimeType: 'image/jpeg',
      data: base64.split(',')[1] || base64
    }
  }));

  const response = await ai.models.generateContent({
    model: modelName,
    contents: { parts: [...imageParts, { text: `Dữ liệu gốc:\n${textContext}` }] },
    config: {
      systemInstruction: `Bạn là một chuyên gia chuyển đổi tài liệu toán học sang LaTeX.

      QUY TẮC BẮT BUỘC:
      1. LOẠI BỎ TOÀN BỘ Header và Footer: Không gõ lại các dòng như "Trang X/Y", "Mã đề...", "Sở Giáo dục và Đào tạo", "Kỳ thi thử...", "Hết".
      2. GIỮ NGUYÊN VĂN BẢN: Các phần "Câu 1.", "Câu 2.", "Lời giải:" và nội dung câu hỏi phải giữ nguyên 100%, không tóm tắt.
      3. CHUYỂN ĐỔI TOÁN HỌC TRIỆT ĐỂ: 
         - Mọi biến số đơn lẻ (x, y, n, a, b, c...), hằng số, số thực, phân số, căn thức, dấu so sánh (>, <, =), đơn vị (cm, m, kg), tập hợp (R, N, Z) PHẢI nằm trong cặp dấu $...$.
         - Ví dụ: Thay vì ghi "x = 1", phải ghi "$x = 1$". Thay vì ghi "cm", phải ghi "$cm$".
      4. KHÔNG SỬ DỤNG MathJax phức tạp, chỉ dùng định dạng LaTeX tiêu chuẩn phù hợp cho MathType.
      5. KHÔNG giải thích, không thêm ghi chú. Chỉ trả về nội dung đã chuyển đổi.

      Đầu ra phải là JSON hợp lệ với trường "latex" (văn bản thuần có dấu $) và "html" (văn bản giữ ngắt dòng bằng thẻ <p>).`,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          latex: { type: Type.STRING },
          html: { type: Type.STRING },
        },
        required: ["latex", "html"]
      },
      temperature: 0,
    }
  });

  try {
    const text = response.text;
    return JSON.parse(text || "{}") as ConversionResult;
  } catch (error) {
    console.error("Lỗi xử lý JSON:", error);
    throw new Error("Mô hình không thể tạo dữ liệu sạch. Vui lòng thử lại.");
  }
};

import React, { useState, useEffect } from 'react';
import { FileType, ProcessingFile, ConversionResult } from './types';
import { pdfToImages, docxToHtmlAndImages, downloadFile } from './utils/converters';
import { convertToLatexHtml } from './services/gemini';

declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }
  interface Window {
    aistudio?: AIStudio;
  }
}

const App: React.FC = () => {
  const [currentFile, setCurrentFile] = useState<ProcessingFile | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [hasKey, setHasKey] = useState<boolean>(false);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio) {
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasKey(selected);
      }
    };
    checkKey();
    // Kiểm tra định kỳ để cập nhật trạng thái nếu người dùng vừa chọn key
    const interval = setInterval(checkKey, 2000);
    return () => clearInterval(interval);
  }, []);

  const handleSelectKey = async () => {
    if (window.aistudio) {
      try {
        await window.aistudio.openSelectKey();
        setHasKey(true);
      } catch (e) {
        console.error("Lỗi khi mở chọn Key:", e);
      }
    } else {
      alert("Hệ thống chưa hỗ trợ trình chọn API Key trong môi trường này.");
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const type = file.type as FileType;
    if (type !== FileType.PDF && type !== FileType.DOCX) {
      alert("Chỉ chấp nhận file PDF hoặc Word (.docx)");
      return;
    }
    setCurrentFile({ file, type, status: 'idle', progress: 0 });
  };

  const downloadWord = () => {
    if (!currentFile?.result?.latex) return;

    // Tạo cấu trúc HTML tối giản cho Word
    const content = currentFile.result.latex;
    const lines = content.split('\n').map(line => `<p>${line.trim() === '' ? '&nbsp;' : line}</p>`).join('');

    const html = `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head><meta charset='utf-8'><style>
        body { font-family: 'Times New Roman', serif; font-size: 13pt; line-height: 1.3; }
        p { margin: 0 0 6pt 0; text-align: justify; }
      </style></head>
      <body>${lines}</body></html>
    `;

    downloadFile(html, currentFile.file.name.replace(/\.[^/.]+$/, "") + "_LaTeX.doc", 'application/msword');
  };

  const processFile = async () => {
    if (!currentFile) return;
    setIsProcessing(true);
    setCurrentFile(prev => prev ? { ...prev, status: 'processing', progress: 10, error: undefined } : null);

    try {
      let images: string[] = [];
      let context = "";

      if (currentFile.type === FileType.PDF) {
        images = await pdfToImages(currentFile.file);
        context = "Đây là đề thi PDF. Hãy gõ lại các câu hỏi, bỏ qua header/footer.";
      } else {
        const docResult = await docxToHtmlAndImages(currentFile.file);
        const tempDiv = document.createElement('div');
        tempDiv.innerHTML = docResult.html;
        context = tempDiv.innerText;
        images = docResult.images.slice(0, 3);
      }

      setCurrentFile(prev => prev ? { ...prev, progress: 40 } : null);
      const result = await convertToLatexHtml(images, context);
      setCurrentFile(prev => prev ? { ...prev, status: 'completed', progress: 100, result } : null);
    } catch (err: any) {
      setCurrentFile(prev => prev ? { ...prev, status: 'error', error: err.message } : null);
    } finally {
      setIsProcessing(false);
    }
  };

  return (
