import { GoogleGenAI, Type } from "@google/genai";
import { ConversionResult } from "../types";

export const convertToLatexHtml = async (
  base64Images: string[],
  textContext: string = ""
): Promise<ConversionResult> => {
  // Khởi tạo instance mới để luôn nhận API Key cập nhật từ môi trường
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Sử dụng Gemini 3 Pro để có khả năng suy luận và tuân thủ định dạng tốt nhất
  const modelName = 'gemini-3-pro-preview';

  const imageParts = base64Images.map(base64 => ({
    inlineData: {
      mimeType: 'image/jpeg',
      data: base64.split(',')[1] || base64
    }
  }));

  const response = await ai.models.generateContent({
    model: modelName,
    contents: { parts: [...imageParts, { text: `Dữ liệu đầu vào:\n${textContext}` }] },
    config: {
      systemInstruction: `Bạn là chuyên gia số hóa đề thi toán học chuyên nghiệp.

      NHIỆM VỤ CỐT LÕI:
      1. LOẠI BỎ TRIỆT ĐỂ: Không gõ lại bất kỳ nội dung nào thuộc về Header, Footer, số trang (Trang 1/4), mã đề, tên sở giáo dục, tên trường, hoặc các dòng kẻ phân cách lề.
      2. GIỮ NGUYÊN VĂN BẢN GỐC: Chỉ gõ lại nội dung câu hỏi và đáp án. Không tóm tắt, không giải thích.
      3. CHUẨN LATEX CHO MATHTYPE: 
         - BẮT BUỘC bao bọc TẤT CẢ ký hiệu toán học vào cặp dấu $...$. 
         - Ngay cả một biến số đơn lẻ (x, y, z, a, b, n...) hoặc một con số trong biểu thức cũng PHẢI nằm trong $...$.
         - Ví dụ: "Cho x thuộc R" -> "Cho $x$ thuộc $\mathbb{R}$".
         - Ví dụ: "AB = 5cm" -> "$AB = 5$ $cm$".
         - Không sử dụng các môi trường phức tạp như \\begin{equation}, chỉ dùng $...$ cho công thức nằm trong dòng và $$...$$ cho công thức đứng riêng dòng.
      4. ĐỊNH DẠNG: Sử dụng LaTeX tiêu chuẩn, không dùng các package lạ mà MathType không đọc được.

      Trả về JSON: {"latex": "nội dung văn bản và công thức", "html": "văn bản có thẻ <p> để giữ hàng"}.`,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          latex: { type: Type.STRING },
          html: { type: Type.STRING },
        },
        required: ["latex", "html"]
      },
      temperature: 0,
    }
  });

  try {
    return JSON.parse(response.text || "{}") as ConversionResult;
  } catch (error) {
    console.error("Lỗi phân tích JSON:", error);
    throw new Error("Không thể xử lý dữ liệu. Vui lòng kiểm tra lại file hoặc API Key.");
  }
};

