  const modelName = 'gemini-3-pro-preview';

  const imageParts = base64Images.map(base64 => ({
    inlineData: {
      mimeType: 'image/jpeg',
      data: base64.split(',')[1] || base64
    }
  }));

  const response = await ai.models.generateContent({
    model: modelName,
    contents: { parts: [...imageParts, { text: `Dữ liệu gốc:\n${textContext}` }] },
    config: {
      systemInstruction: `Bạn là một trợ lý số hóa tài liệu toán học cực kỳ chính xác.

      QUY TẮC CỐT LÕI:
      1. GIỮ NGUYÊN VĂN BẢN GỐC: Các phần chữ bình thường (như "Câu 1. Cho tam giác", "Lời giải", "Đáp án") PHẢI được gõ lại y hệt, không thay đổi dù chỉ một dấu phẩy.
      2. CHUYỂN TOÁN HỌC SANG LATEX: Chỉ những ký hiệu toán học, biến số (x, y, n), tên điểm/hình (ABC, d, P), biểu thức, số thực, đơn vị tính toán mới được chuyển sang LaTeX.
      3. DẤU BAO BỌC BẮT BUỘC: Sử dụng cặp dấu \\( ... \\) cho TẤT CẢ các nội dung toán học. KHÔNG ĐƯỢC DÙNG dấu $ $.
         Ví dụ: "Cho tam giác ABC" chuyển thành "Cho tam giác \\(ABC\\)".
         Ví dụ: "x = 5" chuyển thành "\\(x = 5\\)".
      4. LOẠI BỎ RÁC: Tuyệt đối không gõ lại Header/Footer (Trang số, Mã đề, Tên Sở/Trường, các dòng kẻ lề).
      5. ĐỊNH DẠNG: Chỉ trả về nội dung sạch sẽ dưới dạng JSON.`,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          latex: { type: Type.STRING },
          html: { type: Type.STRING },
        },
        required: ["latex", "html"]
      },
      temperature: 0,
    }
  });

  try {
    return JSON.parse(response.text || "{}") as ConversionResult;
  } catch (error) {
    console.error("Lỗi phân tích JSON:", error);
    throw new Error("Mô hình không thể tạo dữ liệu sạch. Vui lòng kiểm tra lại tài liệu.");
  }
};

