import { GoogleGenAI, Type } from "@google/genai";
import { ConversionResult } from "../types";

export const convertToLatexHtml = async (
  base64Images: string[],
  textContext: string = ""
): Promise<ConversionResult> => {
  // Khởi tạo instance với API Key từ môi trường
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-pro-preview';

  const imageParts = base64Images.map(base64 => ({
    inlineData: {
      mimeType: 'image/jpeg',
      data: base64.split(',')[1] || base64
    }
  }));

  const response = await ai.models.generateContent({
    model: modelName,
    contents: { parts: [...imageParts, { text: `Dữ liệu gốc:\n${textContext}` }] },
    config: {
      systemInstruction: `Bạn là một chuyên gia số hóa đề thi toán học sang LaTeX chất lượng cao.

      QUY TẮC CỐT LÕI:
      1. GIỮ NGUYÊN VĂN BẢN TIẾNG VIỆT: Các phần dẫn như "Câu 1.", "Cho hàm số", "Lời giải:" PHẢI được giữ nguyên 100% nội dung và dấu câu.
      2. CÔNG THỨC TOÁN HỌC: 
         - BẮT BUỘC sử dụng cặp dấu \\( ... \\) cho mọi ký hiệu, biến số và biểu thức. 
         - Tuyệt đối KHÔNG sử dụng dấu $ $.
      3. XỬ LÝ BẢNG (TABLE): 
         - Chuyển các bảng dữ liệu thông thường sang môi trường \\begin{tabular} ... \\end{tabular}.
      4. BẢNG BIẾN THIÊN (VARIATION TABLES): 
         - Chuyển bảng biến thiên thành một bảng LaTeX đơn giản. 
         - Sử dụng các ký hiệu mũi tên: \\uparrow, \\downarrow, \\nearrow, \\searrow để thể hiện chiều biến thiên của hàm số trong bảng.
      5. LOẠI BỎ RÁC: Không gõ lại Header (Tên trường, Sở GD, Mã đề) và Footer (Số trang, chữ "Hết").
      6. ĐỊNH DẠNG ĐẦU RA: Trả về JSON chứa văn bản LaTeX sạch sẽ.`,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          latex: { type: Type.STRING },
          html: { type: Type.STRING },
        },
        required: ["latex", "html"]
      },
      temperature: 0,
    }
  });

  try {
    return JSON.parse(response.text || "{}") as ConversionResult;
  } catch (error) {
    console.error("Lỗi phân tích JSON:", error);
    throw new Error("Mô hình không thể xử lý bảng hoặc công thức phức tạp này. Vui lòng thử lại.");
  }
};

