import { GoogleGenAI, Type } from "@google/genai";
import { ConversionResult } from "../types";

export const convertToLatexHtml = async (
  base64Images: string[],
  textContext: string = ""
): Promise<ConversionResult> => {
  // Khởi tạo instance với API Key từ môi trường
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-pro-preview';

  const imageParts = base64Images.map(base64 => ({
    inlineData: {
      mimeType: 'image/jpeg',
      data: base64.split(',')[1] || base64
    }
  }));

  const response = await ai.models.generateContent({
    model: modelName,
    contents: { parts: [...imageParts, { text: `Dữ liệu gốc cần chuyển đổi:\n${textContext}` }] },
    config: {
      systemInstruction: `Bạn là chuyên gia chuyển đổi tài liệu toán học sang LaTeX chuyên nghiệp, tối ưu cho việc copy vào MathType.

QUY TẮC CỐT LÕI:
1. CÔNG THỨC TOÁN HỌC:
   - BẮT BUỘC sử dụng cặp dấu $$ ... $$ cho mọi ký hiệu, biến số (x, y, z), tên điểm (A, B, C), và biểu thức toán học.
   - Đảm bảo các biến số trong $$ được viết đúng chuẩn LaTeX để tự động in nghiêng (ví dụ: $$x$$, $$y$$, $$ABC$$).
   - Tuyệt đối KHÔNG sử dụng \\( \\) hoặc $ $.

2. GIỮ NGUYÊN VĂN BẢN TIẾNG VIỆT:
   - Giữ nguyên 100% các nhãn như "Câu 1.", "Câu 2.", "Lời giải:", "Đáp án:" và các đoạn văn bản giải thích tiếng Việt.
   - Không tóm tắt, không dịch, không thay đổi dấu câu của phần văn bản thường.

3. XỬ LÝ BẢNG (TABLE):
   - Chuyển đổi các bảng dữ liệu sang môi trường \\begin{tabular} ... \\end{tabular}.
   - Sử dụng các đường kẻ bảng cơ bản nếu cần.

4. BẢNG BIẾN THIÊN (VARIATION TABLES):
   - Chuyển đổi bảng biến thiên thành cấu trúc bảng LaTeX đơn giản.
   - Sử dụng các ký hiệu mũi tên chuẩn: \\uparrow, \\downarrow, \\nearrow, \\searrow để chỉ hướng biến thiên của hàm số.

5. LOẠI BỎ THÀNH PHẦN THỪA:
   - Không gõ lại Header (Tên trường, Sở GD, Mã đề) và Footer (Số trang, "Hết").

Trả về JSON: {"latex": "nội dung văn bản và công thức", "html": "văn bản có thẻ <p> để giữ hàng"}.`,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          latex: { type: Type.STRING },
          html: { type: Type.STRING },
        },
        required: ["latex", "html"]
      },
      temperature: 0,
    }
  });

  try {
    return JSON.parse(response.text || "{}") as ConversionResult;
  } catch (error) {
    console.error("Lỗi phân tích JSON:", error);
    throw new Error("Mô hình gặp khó khăn khi xử lý cấu trúc này. Vui lòng kiểm tra lại file.");
  }
};

import React, { useState, useEffect } from 'react';
import { FileType, ProcessingFile, ConversionResult } from './types';
import { pdfToImages, docxToHtmlAndImages, downloadFile } from './utils/converters';
import { convertToLatexHtml } from './services/gemini';

declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }
  interface Window {
    aistudio?: AIStudio;
  }
}

const App: React.FC = () => {
  const [currentFile, setCurrentFile] = useState<ProcessingFile | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [hasKey, setHasKey] = useState<boolean>(false);

  useEffect(() => {
    const checkKeyStatus = async () => {
      if (window.aistudio) {
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasKey(selected);
      }
    };
    checkKeyStatus();
    const timer = setInterval(checkKeyStatus, 2000);
    return () => clearInterval(timer);
  }, []);

  const handleSetupKey = async () => {
    if (window.aistudio) {
      try {
        await window.aistudio.openSelectKey();
        setHasKey(true);
      } catch (e) {
        console.error("Lỗi mở trình chọn Key:", e);
      }
    } else {
      alert("Hệ thống quản lý Key chỉ khả dụng trong môi trường AI Studio.");
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const type = file.type as FileType;
    if (type !== FileType.PDF && type !== FileType.DOCX) {
      alert("Chỉ chấp nhận file PDF hoặc Word (.docx)");
      return;
    }
    setCurrentFile({ file, type, status: 'idle', progress: 0 });
  };

  const downloadDoc = () => {
    if (!currentFile?.result?.latex) return;

    const content = currentFile.result.latex;
    const lines = content.split('\n').map(l => `<p style="margin:0 0 10pt 0;">${l.trim() === '' ? '&nbsp;' : l}</p>`).join('');

    const htmlWrapper = `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head><meta charset='utf-8'><style>
        body { font-family: 'Times New Roman', serif; font-size: 13pt; line-height: 1.5; text-align: justify; }
      </style></head>
      <body>${lines}</body></html>
    `;

    downloadFile(htmlWrapper, currentFile.file.name.replace(/\.[^/.]+$/, "") + "_Convert.doc", 'application/msword');
  };

  const processFile = async () => {
    if (!currentFile) return;
    setIsProcessing(true);
    setCurrentFile(prev => prev ? { ...prev, status: 'processing', progress: 10, error: undefined } : null);

    try {
      let images: string[] = [];
      let textData = "";

      if (currentFile.type === FileType.PDF) {
        images = await pdfToImages(currentFile.file);
        textData = "Yêu cầu: Giữ nguyên văn bản, chuyển công thức sang $$ $$, xử lý Bảng và Bảng biến thiên chuẩn LaTeX.";
      } else {
        const res = await docxToHtmlAndImages(currentFile.file);
        const div = document.createElement('div');
        div.innerHTML = res.html;
        textData = div.innerText;
        images = res.images.slice(0, 10); // Lấy nhiều ảnh hơn để đảm bảo nhận diện bảng tốt
      }

      setCurrentFile(prev => prev ? { ...prev, progress: 40 } : null);
      const result = await convertToLatexHtml(images, textData);
      setCurrentFile(prev => prev ? { ...prev, status: 'completed', progress: 100, result } : null);
    } catch (err: any) {
      setCurrentFile(prev => prev ? { ...prev, status: 'error', error: err.message } : null);
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#f1f5f9] text-slate-900 font-sans p-4 md:p-8">
      {/* Header */}
      <nav className="max-w-5xl mx-auto flex items-center justify-between mb-8 bg-white p-6 rounded-[2.5rem] shadow-sm border border-slate-200/50">
        <div className="flex items-center gap-4">
          <div className="w-14 h-14 bg-blue-700 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-blue-100">
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="w-8 h-8"><path d="M11.25 4.533A9.707 9.707 0 006 3a9.735 9.735 0 00-3.25.555.75.75 0 00-.5.707v14.25a.75.75 0 001 .707A8.237 8.237 0 016 18.75c1.995 0 3.823.707 5.25 1.886V4.533zM12.75 20.636A8.214 8.214 0 0118 18.75c1.026 0 1.99.191 2.875.539a.75.75 0 001-.707V4.262a.75.75 0 00-.5-.707A9.735 9.735 0 0018 3a9.707 9.707 0 00-5.25 1.533v16.103z" /></svg>
          </div>
          <div>
            <h1 className="text-2xl font-black text-slate-800 tracking-tight">Math<span className="text-blue-700">Converter</span></h1>
            <p className="text-[11px] font-bold text-slate-400 uppercase tracking-widest">Định dạng $$...$$ &bull; Bảng biểu &bull; Bảng biến thiên</p>
          </div>
        </div>

        <button 
          onClick={handleSetupKey}
          className={`px-6 py-3 rounded-2xl text-xs font-black transition-all shadow-xl active:scale-95 border-b-4 ${hasKey ? 'bg-emerald-500 border-emerald-700 text-white' : 'bg-slate-900 border-slate-700 text-white'}`}
        >
          {hasKey ? 'API SẴN SÀNG' : 'THIẾT LẬP API KEY'}
        </button>
      </nav>

      <main className="max-w-5xl mx-auto">
        {!currentFile ? (
          <div 
            className="group relative bg-white border-2 border-dashed border-slate-200 rounded-[3rem] p-24 text-center hover:border-blue-400 hover:bg-blue-50/10 transition-all cursor-pointer shadow-sm"
            onClick={() => document.getElementById('file-input')?.click()}
          >
            <input id="file-input" type="file" className="hidden" accept=".pdf,.docx" onChange={handleFileUpload} />
            <div className="w-24 h-24 bg-blue-50 text-blue-600 rounded-[2rem] flex items-center justify-center mx-auto mb-8 group-hover:scale-110 transition-all">
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-12 h-12"><path strokeLinecap="round" strokeLinejoin="round" d="M3 16.5v2.25A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75V16.5m-13.5-9L12 3m0 0l4.5 4.5M12 3v13.5" /></svg>
            </div>
            <h2 className="text-3xl font-black text-slate-800 mb-4">Tải lên tài liệu gốc</h2>
            <p className="text-slate-400 font-medium max-w-sm mx-auto leading-relaxed">
              Tự động chuyển công thức sang $$ $$, dựng bảng biến thiên và bảng dữ liệu chuẩn LaTeX.
            </p>
          </div>
        ) : (
          <div className="bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 overflow-hidden flex flex-col h-[80vh]">
            <div className="border-b border-slate-100 p-6 flex items-center justify-between">
              <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-white font-black text-xs shadow-lg ${currentFile.type === FileType.PDF ? 'bg-rose-500' : 'bg-blue-600'}`}>
                  {currentFile.type === FileType.PDF ? 'PDF' : 'DOCX'}
                </div>
                <h3 className="font-bold text-slate-800 text-lg truncate max-w-sm">{currentFile.file.name}</h3>
              </div>

              <div className="flex gap-2">
                {currentFile.status === 'idle' && (
                  <button 
                    onClick={processFile} 
                    className="bg-blue-700 text-white px-10 py-3 rounded-2xl text-sm font-black shadow-xl hover:bg-blue-800 transition-all active:translate-y-1"
                  >
                    Bắt đầu số hóa
                  </button>
                )}
                <button onClick={() => setCurrentFile(null)} className="p-3 text-slate-300 hover:text-slate-900 transition-colors"><svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={3} stroke="currentColor" className="w-6 h-6"><path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" /></svg></button>
              </div>
