            <div className="flex-grow overflow-hidden relative">
              {currentFile.status === 'processing' && (
                <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-white/95">
                  <div className="w-16 h-16 border-4 border-blue-100 border-t-blue-700 rounded-full animate-spin mb-6"></div>
                  <h4 className="text-xl font-black text-slate-800">Đang gõ chính xác $$...$$</h4>
                  <p className="text-slate-400 font-medium mt-2">Đang xử lý Bảng biến thiên & Bảng biểu</p>
                </div>
              )}

              {currentFile.status === 'completed' && currentFile.result && (
                <div className="flex flex-col h-full">
                  <div className="bg-slate-50 border-b border-slate-100 px-8 py-4 flex items-center justify-between">
                    <span className="text-[10px] font-black uppercase text-slate-500 tracking-[0.3em]">Kết quả số hóa (Chuẩn MathType)</span>
                    <div className="flex gap-3">
                      <button onClick={downloadDoc} className="bg-emerald-600 text-white px-6 py-2.5 rounded-xl text-xs font-black shadow-lg hover:bg-emerald-700 transition-all">
