import { GoogleGenAI, Type } from "@google/genai";
import { ConversionResult } from "../types";

export const convertToLatexHtml = async (
  base64Images: string[],
  textContext: string = ""
): Promise<ConversionResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-pro-preview';

  const imageParts = base64Images.map(base64 => ({
    inlineData: {
      mimeType: 'image/jpeg',
      data: base64.split(',')[1] || base64
    }
  }));

  const response = await ai.models.generateContent({
    model: modelName,
    contents: { parts: [...imageParts, { text: `Dữ liệu gốc từ tài liệu:\n${textContext}` }] },
    config: {
      systemInstruction: `Bạn là một máy đánh máy chuyên nghiệp, có nhiệm vụ số hóa tài liệu toán học sang định dạng văn bản kết hợp LaTeX.

NHIỆM VỤ CHI TIẾT:
1. GÕ LẠI VĂN BẢN (RETYPING):
   - Chỉ gõ lại chính xác những gì xuất hiện trong tài liệu gốc.
   - Giữ nguyên các nhãn "Câu 1.", "Câu 2.", "Ví dụ:", "Lời giải:", "Đáp án:".
   - TUYỆT ĐỐI KHÔNG thêm bất kỳ lời dẫn, giải thích, tóm tắt hay câu từ nào khác vào.
   - TUYỆT ĐỐI KHÔNG bỏ sót chữ nào trong phần văn bản tiếng Việt.

2. ĐỊNH DẠNG CÔNG THỨC TOÁN HỌC (MATHTYPE COMPATIBLE):
   - TẤT CẢ các ký hiệu toán học, biến số (x, y, n...), tên điểm (A, B, C...), tên hình, biểu thức, số đo phải được bao bọc bởi cặp dấu $$ (ví dụ: $$x$$, $$ABC$$, $$y = f(x)$$, $$60^\circ$$).
   - Việc đặt trong $$ sẽ giúp MathType nhận diện và tự động in nghiêng các biến số.
   - KHÔNG sử dụng dấu $ đơn hay dấu \\( \\).

3. BẢNG BIỂU (TABLE):
   - Chuyển các bảng dữ liệu sang định dạng LaTeX: \\begin{tabular} ... \\end{tabular}.

4. BẢNG BIẾN THIÊN (VARIATION TABLE):
   - Chuyển bảng biến thiên thành cấu trúc bảng đơn giản.
   - Sử dụng các ký hiệu mũi tên LaTeX sau để chỉ chiều biến thiên: \\uparrow (lên đứng), \\downarrow (xuống đứng), \\nearrow (lên chéo), \\searrow (xuống chéo).

5. LOẠI BỎ RÁC (HEADER/FOOTER):
   - Bỏ qua hoàn toàn các thông tin Header (Tên trường, Sở GD, Mã đề, Kì thi) và Footer (Số trang, "Hết").

Trả về kết quả dưới dạng JSON:
{
  "latex": "Nội dung đã gõ lại với công thức trong $$",
  "html": "Nội dung tương tự nhưng định dạng thẻ <p> cho mỗi dòng"
}`,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          latex: { type: Type.STRING },
          html: { type: Type.STRING },
        },
        required: ["latex", "html"]
      },
      temperature: 0,
    }
  });

  try {
    return JSON.parse(response.text || "{}") as ConversionResult;
  } catch (error) {
    console.error("Lỗi phân tích JSON:", error);
    throw new Error("Mô hình không thể xử lý chính xác tài liệu này. Vui lòng thử lại với file rõ nét hơn.");
  }
};

