import { GoogleGenAI, Type } from "@google/genai";
import { ConversionResult } from "../types";

export const convertToLatexHtml = async (
  base64Images: string[],
  textContext: string = ""
): Promise<ConversionResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-pro-preview';

  const imageParts = base64Images.map(base64 => ({
    inlineData: {
      mimeType: 'image/jpeg',
      data: base64.split(',')[1] || base64
    }
  }));

  const response = await ai.models.generateContent({
    model: modelName,
    contents: { parts: [...imageParts, { text: `Dữ liệu gốc từ tài liệu:\n${textContext}` }] },
    config: {
      systemInstruction: `Bạn là một trợ lý số hóa tài liệu toán học có độ chính xác tuyệt đối. Nhiệm vụ của bạn là gõ lại văn bản từ hình ảnh/dữ liệu được cung cấp.

QUY TẮC CỐT LÕI (PHẢI TUÂN THỦ):
1. ĐỊNH DẠNG CÔNG THỨC VÀ BIẾN SỐ:
   - CHỈ sử dụng cặp dấu $$ để bao bọc công thức toán học, biến số, ký hiệu, hoặc tên các điểm.
   - Ví dụ đúng: "Cho tam giác $$ABC$$ có cạnh $$a=3$$, $$b=4$$."
   - Ví dụ sai (bao bọc thừa): "$$Cho tam giác ABC$$" hoặc "$$Câu 1. Cho tam giác ABC$$".
   - Mọi ký hiệu toán học riêng lẻ như $$x$$, $$y$$, $$z$$, $$f(x)$$, $$\sin(x)$$, $$60^\circ$$, $$\Delta$$ đều phải nằm trong $$.

2. CHỈ GÕ LẠI (NO ADDITIONS):
   - Tuyệt đối không thêm bất kỳ lời dẫn, giải thích, tóm tắt hay câu từ nào không có trong bản gốc.
   - Giữ nguyên các nhãn "Câu 1.", "Câu 2.", "Lời giải:", "Ví dụ:".
   - Không được gõ lại phần Header (Tiêu đề trường, sở, mã đề) và Footer (Số trang, chữ "Hết").

3. XỬ LÝ BẢNG (TABLE):
   - Chuyển các bảng dữ liệu thông thường sang môi trường \\begin{tabular} ... \\end{tabular}.

4. BẢNG BIẾN THIÊN (VARIATION TABLES):
   - Chuyển thành bảng đơn giản.
   - Sử dụng các mũi tên: \\uparrow, \\downarrow, \\nearrow, \\searrow để chỉ chiều biến thiên.

5. NGÔN NGỮ:
   - Giữ nguyên văn bản tiếng Việt chính xác như bản gốc.

Trả về kết quả dưới dạng JSON:
{
  "latex": "Văn bản gõ lại với các ký hiệu toán học nằm trong $$ ... $$",
  "html": "Nội dung tương tự định dạng trong các thẻ <p>"
}`,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          latex: { type: Type.STRING },
          html: { type: Type.STRING },
        },
        required: ["latex", "html"]
      },
      temperature: 0,
    }
  });

  try {
    return JSON.parse(response.text || "{}") as ConversionResult;
  } catch (error) {
    console.error("Lỗi phân tích JSON:", error);
    throw new Error("Mô hình không thể xử lý chính xác tài liệu này. Vui lòng thử lại.");
  }
};

