          </div>
          <div>
            <h1 className="text-2xl font-black text-slate-800 tracking-tight">Math<span className="text-blue-600">Retype</span></h1>
            <p className="text-[11px] font-bold text-slate-400 uppercase tracking-widest">Sạch nội dung &bull; Chuẩn $$ MathType</p>
          </div>
        </div>

        <button 
          onClick={handleSetupKey}
          className={`px-8 py-3 rounded-2xl text-xs font-black transition-all shadow-xl active:scale-95 border-b-4 ${hasKey ? 'bg-emerald-500 border-emerald-700 text-white' : 'bg-slate-900 border-slate-700 text-white'}`}
        >
          {hasKey ? 'HỆ THỐNG SẴN SÀNG' : 'THIẾT LẬP API KEY'}
        </button>
      </nav>

      <main className="max-w-5xl mx-auto">
        {!currentFile ? (
          <div 
            className="group relative bg-white border-2 border-dashed border-slate-200 rounded-[3rem] p-24 text-center hover:border-blue-400 hover:bg-blue-50/10 transition-all cursor-pointer shadow-sm"
            onClick={() => document.getElementById('file-input')?.click()}
          >
            <input id="file-input" type="file" className="hidden" accept=".pdf,.docx" onChange={handleFileUpload} />
            <div className="w-24 h-24 bg-blue-50 text-blue-600 rounded-3xl flex items-center justify-center mx-auto mb-8 group-hover:scale-110 transition-transform duration-300">
