              <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-white font-black text-xs shadow-lg ${currentFile.type === FileType.PDF ? 'bg-rose-500' : 'bg-blue-600'}`}>
                  {currentFile.type === FileType.PDF ? 'PDF' : 'DOCX'}
                </div>
                <h3 className="font-bold text-slate-800 text-lg truncate max-w-sm">{currentFile.file.name}</h3>
              </div>

              <div className="flex gap-2">
                {currentFile.status === 'idle' && (
                  <button 
