import { GoogleGenAI, Type } from "@google/genai";
import { ConversionResult } from "../types";

export const convertToLatexHtml = async (
  base64Images: string[],
  textContext: string = ""
): Promise<ConversionResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-pro-preview';

  const imageParts = base64Images.map(base64 => ({
    inlineData: {
      mimeType: 'image/jpeg',
      data: base64.split(',')[1] || base64
    }
  }));

  const response = await ai.models.generateContent({
    model: modelName,
    contents: { parts: [...imageParts, { text: `Dữ liệu gốc:\n${textContext}` }] },
    config: {
      systemInstruction: `Bạn là một máy đánh máy chuyên nghiệp chuyên số hóa tài liệu toán học Việt Nam. Hãy gõ lại tài liệu từ hình ảnh/văn bản cung cấp theo các quy tắc nghiêm ngặt sau:

1. ĐỊNH DẠNG TOÁN HỌC:
   - TẤT CẢ các công thức, biến số (x, y...), và ĐỈNH HÌNH HỌC (A, B, C, ABC, S.ABCD) PHẢI nằm trong cặp dấu $ đơn (ví dụ: $x^2 + 1$, $ABC$, $S.ABCD$).
   - Trong LaTeX, chữ cái trong $ sẽ tự động in nghiêng.
   - Sử dụng \\begin{cases} ... \\end{cases} cho các hệ phương trình hoặc hệ điều kiện.
   - Ký hiệu ĐỘ sử dụng ^\\circ (ví dụ: $60^\\circ$).

2. CHỈ GÕ LẠI (STRICT RETYPING):
   - Chỉ gõ lại chính xác nội dung văn bản. Không thêm lời dẫn, không giải thích.
   - Giữ nguyên định dạng "Câu 1.", "Câu 2.", và các phương án "A.", "B.", "C.", "D.".
   - Tuyệt đối bỏ qua phần Header (Tên trường, Sở, Mã đề) và Footer (Số trang, chữ "Hết").

3. BẢNG BIẾN THIÊN (BBT):
   - KHÔNG dùng mã \\begin{tabular}. Trình bày BBT dưới dạng bảng văn bản đơn giản bằng các ký tự gạch đứng | và gạch ngang -.
   - Sử dụng mũi tên: \\nearrow (cho hướng lên) và \\searrow (cho hướng xuống).
   - Ví dụ minh họa BBT:
     x | -\infty   0   +\infty
     --|---------------------
     y'|     +     |     -
     --|---------------------
     y | -\infty \nearrow 1 \searrow -\infty

4. HÌNH VẼ MINH HỌA:
   - Tại vị trí có hình vẽ đồ thị, hình khối hoặc sơ đồ, hãy chèn dòng chữ: [Có hình vẽ minh họa] ngay trong câu đó.

5. CẤU TRÚC PHƯƠNG ÁN:
   - Luôn giữ đúng cấu trúc các lựa chọn A, B, C, D trên các dòng riêng biệt hoặc theo đúng bản gốc.

Trả về kết quả dưới dạng JSON:
{
  "latex": "Nội dung văn bản gõ lại hoàn chỉnh theo quy tắc trên",
  "html": "Nội dung văn bản tương ứng"
}`,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          latex: { type: Type.STRING },
          html: { type: Type.STRING },
        },
        required: ["latex", "html"]
      },
      temperature: 0,
    }
  });

  try {
    return JSON.parse(response.text || "{}") as ConversionResult;
  } catch (error) {
    console.error("Lỗi phân tích JSON:", error);
    throw new Error("Không thể xử lý tài liệu. Vui lòng thử lại với hình ảnh rõ nét hơn.");
  }
};

import React, { useState, useEffect } from 'react';
