declare const pdfjsLib: any;
declare const mammoth: any;

if (typeof window !== 'undefined' && (window as any).pdfjsLib) {
    (window as any).pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

export const fileToDataUrl = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const pdfToImages = async (file: File): Promise<string[]> => {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  const imageUrls: string[] = [];

  for (let i = 1; i <= pdf.numPages; i++) {
    const page = await pdf.getPage(i);
    const viewport = page.getViewport({ scale: 2.0 });
    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d');
    canvas.height = viewport.height;
    canvas.width = viewport.width;

    await page.render({ canvasContext: context, viewport }).promise;
    imageUrls.push(canvas.toDataURL('image/jpeg', 0.8));
    if (i >= 10) break; 
  }
  return imageUrls;
};

export const docxToHtmlAndImages = async (file: File): Promise<{ html: string, images: string[] }> => {
  const arrayBuffer = await file.arrayBuffer();
  const images: string[] = [];
  const options = {
    convertImage: mammoth.images.inline((element: any) => {
      return element.read("base64").then((imageBuffer: any) => {
        const base64 = `data:${element.contentType};base64,${imageBuffer.base64}`;
        images.push(base64);
        return { src: base64 };
      });
    })
  };
  const result = await mammoth.convertToHtml({ arrayBuffer }, options);
  return { html: result.value, images };
};

export const downloadAsWord = (latexContent: string, sourceImages: string[], fileName: string) => {
  // Replace [[IMG_n]] with actual <img> tags
  let richContent = latexContent;

  // Convert newlines to <br> or <p> for HTML Word doc
  const lines = richContent.split('\n').map(line => {
    let processed = line.trim();
    if (!processed) return '<p>&nbsp;</p>';

    // Inject images
    processed = processed.replace(/\[\[IMG_(\d+)\]\]/g, (match, p1) => {
      const index = parseInt(p1);
      if (sourceImages && sourceImages[index]) {
        return `<div style="text-align:center;margin:10pt 0;"><img src="${sourceImages[index]}" style="max-width:100%; height:auto;" /></div>`;
      }
      return '';
    });

    return `<p style="margin:0 0 10pt 0; font-family:'Times New Roman', serif; font-size:13pt;">${processed}</p>`;
  }).join('');

  const htmlWrapper = `
    <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
    <head><meta charset='utf-8'><style>
      body { font-family: 'Times New Roman', serif; }
    </style></head>
    <body>${lines}</body></html>
  `;

  const blob = new Blob([htmlWrapper], { type: 'application/msword' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = fileName;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  URL.revokeObjectURL(url);
};

