import { GoogleGenAI, Type } from "@google/genai";
import { ConversionResult } from "../types";

export const convertToLatexHtml = async (
  base64Images: string[],
  textContext: string = ""
): Promise<ConversionResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-pro-preview';

  const imageParts = base64Images.map(base64 => ({
    inlineData: {
      mimeType: 'image/jpeg',
      data: base64.split(',')[1] || base64
    }
  }));

  const response = await ai.models.generateContent({
    model: modelName,
    contents: { parts: [...imageParts, { text: `Dữ liệu gốc:\n${textContext}` }] },
    config: {
      systemInstruction: `Bạn là chuyên gia số hóa tài liệu toán học. Hãy gõ lại tài liệu và nhận diện vùng hình ảnh theo các quy tắc:

1. ĐỊNH DẠNG TOÁN HỌC:
   - Bao quanh công thức, biến số, đỉnh hình học bằng MỘT dấu $ (Ví dụ: $x^2$, $ABC$).
   - Hệ phương trình dùng \\begin{cases}. Ký hiệu độ dùng ^\\circ.

2. NHẬN DIỆN VÀ CẮT HÌNH (QUAN TRỌNG NHẤT):
   - Khi thấy hình vẽ, đồ thị, hoặc BBT, hãy chèn thẻ [[FIG_ID]] (với ID tự đặt, ví dụ FIG_0, FIG_1).
   - Bạn PHẢI trả về tọa độ vùng bao (bounding box) cho mỗi thẻ này trong danh sách "figures".
   - VÙNG BAO PHẢI ÔM SÁT HÌNH VẼ NHẤT CÓ THỂ. Tuyệt đối KHÔNG bao gồm chữ dẫn của câu hỏi, không bao gồm các phương án A, B, C, D. Chỉ lấy phần "hình" hoặc phần "bảng".
   - Tọa độ [ymin, xmin, ymax, xmax] chuẩn hóa từ 0-1000.

3. TRÌNH BÀY BBT:
   - Ngoài việc cắt hình, hãy vẫn gõ lại BBT dạng văn bản đơn giản dùng | và - (không dùng định dạng bảng markdown ---).
   - Dùng \\nearrow và \\searrow.

4. CẤU TRÚC VĂN BẢN:
   - Giữ nguyên Câu 1, Câu 2... và các phương án.
   - Bỏ qua Header và Footer.

Trả về JSON theo schema cung cấp.`,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          latex: { type: Type.STRING },
          html: { type: Type.STRING },
          figures: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING, description: "ID tương ứng trong văn bản, ví dụ FIG_0" },
                source_index: { type: Type.INTEGER, description: "Chỉ số ảnh đầu vào (0, 1, 2...)" },
                box_2d: { 
                  type: Type.ARRAY, 
                  items: { type: Type.NUMBER },
                  description: "[ymin, xmin, ymax, xmax] từ 0-1000"
                }
              },
              required: ["id", "source_index", "box_2d"]
            }
          }
        },
        required: ["latex", "html"]
      },
      temperature: 0,
    }
  });

  try {
    return JSON.parse(response.text || "{}") as ConversionResult;
  } catch (error) {
    console.error("Lỗi phân tích JSON:", error);
    throw new Error("Không thể xử lý. Vui lòng thử lại.");
  }
};

declare const pdfjsLib: any;
declare const mammoth: any;

if (typeof window !== 'undefined' && (window as any).pdfjsLib) {
    (window as any).pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

export const fileToDataUrl = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Cắt ảnh từ base64 dựa trên tọa độ chuẩn hóa [ymin, xmin, ymax, xmax] (0-1000)
 */
export const cropImage = (base64: string, box: number[]): Promise<string> => {
  return new Promise((resolve) => {
    const img = new Image();
    img.onload = () => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return resolve(base64);

      const [ymin, xmin, ymax, xmax] = box;
      const x = (xmin / 1000) * img.width;
      const y = (ymin / 1000) * img.height;
      const width = ((xmax - xmin) / 1000) * img.width;
      const height = ((ymax - ymin) / 1000) * img.height;

      canvas.width = width;
      canvas.height = height;
      ctx.drawImage(img, x, y, width, height, 0, 0, width, height);
      resolve(canvas.toDataURL('image/png'));
    };
    img.src = base64;
  });
};

export const pdfToImages = async (file: File): Promise<string[]> => {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  const imageUrls: string[] = [];
  for (let i = 1; i <= Math.min(pdf.numPages, 10); i++) {
    const page = await pdf.getPage(i);
    const viewport = page.getViewport({ scale: 2.0 });
    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d');
    canvas.height = viewport.height;
    canvas.width = viewport.width;
    await page.render({ canvasContext: context, viewport }).promise;
    imageUrls.push(canvas.toDataURL('image/jpeg', 0.8));
  }
  return imageUrls;
};

export const docxToHtmlAndImages = async (file: File): Promise<{ html: string, images: string[] }> => {
  const arrayBuffer = await file.arrayBuffer();
  const images: string[] = [];
  const options = {
    convertImage: mammoth.images.inline((element: any) => {
      return element.read("base64").then((imageBuffer: any) => {
        const base64 = `data:${element.contentType};base64,${imageBuffer.base64}`;
        images.push(base64);
        return { src: base64 };
      });
    })
  };
  const result = await mammoth.convertToHtml({ arrayBuffer }, options);
  return { html: result.value, images };
};

export const downloadAsWord = async (
  latexContent: string, 
  sourceImages: string[], 
  figures: any[], 
  fileName: string
) => {
  // Chuẩn bị các ảnh đã được cắt
  const croppedMap: Record<string, string> = {};
  if (figures && figures.length > 0) {
    for (const fig of figures) {
      const sourceBase64 = sourceImages[fig.source_index];
      if (sourceBase64) {
        croppedMap[fig.id] = await cropImage(sourceBase64, fig.box_2d);
      }
    }
  }

  const lines = latexContent.split('\n').map(line => {
    let processed = line.trim();
    if (!processed) return '<p>&nbsp;</p>';

    // Thay thế thẻ [[FIG_ID]] bằng ảnh đã cắt
    processed = processed.replace(/\[\[(FIG_\w+)\]\]/g, (match, figId) => {
      if (croppedMap[figId]) {
        return `<div style="text-align:center;margin:15pt 0;"><img src="${croppedMap[figId]}" style="max-width:400pt; height:auto; border:0.5pt solid #eee;" /></div>`;
      }
      return `[Hình vẽ ${figId}]`;
    });

    return `<p style="margin:0 0 8pt 0; font-family:'Times New Roman', serif; font-size:13pt; line-height:1.5;">${processed}</p>`;
  }).join('');

  const htmlWrapper = `
    <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
    <head><meta charset='utf-8'><style>body { font-family: 'Times New Roman', serif; }</style></head>
    <body>${lines}</body></html>
  `;

  const blob = new Blob([htmlWrapper], { type: 'application/msword' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = fileName;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  URL.revokeObjectURL(url);
};

